# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score
import os
import re
import joblib

app = Flask(__name__)

MODEL_PATH = os.environ.get("SPAM_MODEL_PATH", "spam_model.joblib")


def clean_text(text):
    text = text.lower()
    text = re.sub(r"[^a-z0-9\s]", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    return text


def load_training_data():
    spam_texts = [
        "Congratulations you have won a free prize claim now",
        "Limited time offer buy now and save big",
        "Urgent act now to receive your bonus reward",
        "You have been selected for a cash prize",
        "Free money available click here to get it",
        "Exclusive deal for you only today",
        "Win a lottery jackpot by responding quickly",
        "Cheap meds available online no prescription needed",
        "Claim your gift card reward now",
        "Earn money fast from home with no effort",
    ]

    ham_texts = [
        "Hi team the meeting is scheduled for tomorrow",
        "Please review the attached project report",
        "Let's have lunch next week to discuss plans",
        "The invoice for your recent purchase is attached",
        "Can you send me the updated document please",
        "Reminder about the dentist appointment on Friday",
        "Thanks for your help with the presentation",
        "Your package will arrive on Monday",
        "Please find the agenda for today's call",
        "I will be out of office until next Tuesday",
    ]

    texts = spam_texts + ham_texts
    labels = [1] * len(spam_texts) + [0] * len(ham_texts)
    return texts, labels


def train_and_save_model():
    texts, labels = load_training_data()
    texts = [clean_text(t) for t in texts]

    X_train, X_test, y_train, y_test = train_test_split(
        texts, labels, test_size=0.2, random_state=42, stratify=labels
    )

    model = Pipeline([
        ("vectorizer", CountVectorizer()),
        ("clf", LogisticRegression(max_iter=1000))
    ])

    model.fit(X_train, y_train)
    preds = model.predict(X_test)
    acc = accuracy_score(y_test, preds)
    joblib.dump(model, MODEL_PATH)
    return model, acc


def load_model():
    if os.path.exists(MODEL_PATH):
        return joblib.load(MODEL_PATH)
    model, _ = train_and_save_model()
    return model


model = load_model()


@app.route("/predict", methods=["POST"])
def predict():
    data = request.get_json(silent=True) or {}
    text = data.get("text", "")
    if not isinstance(text, str) or not text.strip():
        return jsonify({"error": "Field 'text' must be a non-empty string"}), 400

    cleaned = clean_text(text)
    proba = model.predict_proba([cleaned])[0][1]
    label = "spam" if proba >= 0.5 else "ham"
    return jsonify({
        "spam_probability": float(proba),
        "label": label
    })


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port)